// Route any Gitea system-webhook event to a Mattermost-friendly message.
// Returns {text} for events worth posting, {skip:true} for events to ignore.
// Distinguishes events by the X-Gitea-Event header (passed by Gitea on every
// webhook POST). Body shapes vary per event — see
// https://docs.gitea.com/development/webhooks for the per-event payloads.

const headers = $json.headers || {};
const body = $json.body || {};
const eventType = (headers['x-gitea-event'] || '').toLowerCase();

let text = null;

switch (eventType) {
  case 'push': {
    const repo = body.repository?.full_name || 'unknown';
    const pusher = body.pusher?.username || body.sender?.username || 'someone';
    const ref = (body.ref || '').replace('refs/heads/', '').replace('refs/tags/', 'tag:');
    const commits = body.commits || [];
    if (!commits.length) break;
    const lines = [`:arrow_up: **${pusher}** pushed ${commits.length} commit${commits.length>1?'s':''} to **${repo}** (\`${ref}\`)`];
    for (const c of commits.slice(0, 5)) {
      const msg = (c.message || '').split('\n')[0].slice(0, 90);
      const sha = (c.id || '').slice(0, 7);
      lines.push(`  • [\`${sha}\`](${c.url}) ${msg}`);
    }
    if (commits.length > 5) lines.push(`  • …and ${commits.length-5} more`);
    text = lines.join('\n');
    break;
  }
  case 'pull_request': {
    const pr = body.pull_request || {};
    const action = body.action || 'updated';
    const repo = body.repository?.full_name || 'unknown';
    const user = body.sender?.username || pr.user?.username || 'someone';
    const num = pr.number;
    const title = pr.title || '';
    const url = pr.html_url || pr.url || '';
    let emoji, verb;
    if (action === 'opened')   { emoji = ':rocket:'; verb = 'opened'; }
    else if (action === 'closed' && pr.merged) { emoji = ':white_check_mark:'; verb = 'merged'; }
    else if (action === 'closed') { emoji = ':x:'; verb = 'closed (without merging)'; }
    else if (action === 'reopened') { emoji = ':leftwards_arrow_with_hook:'; verb = 'reopened'; }
    else break; // ignore edit/assign/etc.
    text = `${emoji} **${user}** ${verb} PR [#${num}: ${title}](${url}) in **${repo}**`;
    break;
  }
  case 'pull_request_review': {
    const pr = body.pull_request || {};
    const review = body.review || {};
    const repo = body.repository?.full_name || 'unknown';
    const user = body.sender?.username || 'someone';
    const num = pr.number;
    const title = pr.title || '';
    const url = pr.html_url || pr.url || '';
    const state = (review.state || '').toLowerCase();
    let emoji;
    if (state === 'approved') emoji = ':+1:';
    else if (state === 'rejected' || state === 'request_changes') emoji = ':warning:';
    else if (state === 'commented') emoji = ':speech_balloon:';
    else break;
    text = `${emoji} **${user}** reviewed PR [#${num}: ${title}](${url}) (${state}) in **${repo}**`;
    break;
  }
  case 'issues': {
    const issue = body.issue || {};
    const action = body.action || 'updated';
    const repo = body.repository?.full_name || 'unknown';
    const user = body.sender?.username || issue.user?.username || 'someone';
    const num = issue.number;
    const title = issue.title || '';
    const url = issue.html_url || issue.url || '';
    let emoji, verb;
    if (action === 'opened')   { emoji = ':bug:'; verb = 'opened'; }
    else if (action === 'closed') { emoji = ':checkered_flag:'; verb = 'closed'; }
    else if (action === 'reopened') { emoji = ':leftwards_arrow_with_hook:'; verb = 'reopened'; }
    else break;
    text = `${emoji} **${user}** ${verb} issue [#${num}: ${title}](${url}) in **${repo}**`;
    break;
  }
  case 'issue_comment': {
    const issue = body.issue || {};
    const comment = body.comment || {};
    const action = body.action || '';
    if (action !== 'created') break;
    const repo = body.repository?.full_name || 'unknown';
    const user = body.sender?.username || 'someone';
    const num = issue.number;
    const title = issue.title || '';
    const url = comment.html_url || issue.html_url || '';
    const snippet = (comment.body || '').split('\n')[0].slice(0, 100);
    text = `:speech_balloon: **${user}** commented on [#${num}: ${title}](${url}) in **${repo}**` +
           (snippet ? `\n  > ${snippet}` : '');
    break;
  }
  case 'release': {
    const rel = body.release || {};
    const action = body.action || '';
    if (action !== 'published') break;
    const repo = body.repository?.full_name || 'unknown';
    const user = body.sender?.username || rel.author?.username || 'someone';
    const tag = rel.tag_name || 'untagged';
    const name = rel.name || tag;
    const url = rel.html_url || rel.url || '';
    text = `:tada: **${user}** published [${name}](${url}) (${tag}) in **${repo}**`;
    break;
  }
  case 'create': {
    const repo = body.repository?.full_name || 'unknown';
    const user = body.sender?.username || 'someone';
    const refType = body.ref_type || 'ref';
    const ref = body.ref || '';
    if (refType === 'branch') {
      text = `:herb: **${user}** created branch \`${ref}\` in **${repo}**`;
    } else if (refType === 'tag') {
      text = `:label: **${user}** tagged \`${ref}\` in **${repo}**`;
    }
    break;
  }
  case 'repository': {
    const action = body.action || '';
    const repo = body.repository?.full_name || 'unknown';
    const user = body.sender?.username || 'someone';
    if (action === 'created') text = `:sparkles: **${user}** created new repo **${repo}**`;
    else if (action === 'deleted') text = `:wastebasket: **${user}** deleted repo **${repo}**`;
    break;
  }
  case 'fork': {
    const repo = body.repository?.full_name || 'unknown';
    const forkee = body.forkee?.full_name || 'unknown';
    const user = body.sender?.username || 'someone';
    text = `:fork_and_knife: **${user}** forked **${repo}** → **${forkee}**`;
    break;
  }
}

if (!text) return [{ json: { skip: true, eventType } }];
return [{ json: { text, eventType } }];
